    it('should retrieve adapter by channel', () => {
      const emailAdapter = new EmailAdapter();
      service.registerAdapter(emailAdapter);

      expect(service.getAdapter('email')).toBe(emailAdapter);
      expect(service.getAdapter('sms')).toBeUndefined();
    });
  });

  describe('notification ordering', () => {
    it('should deliver notifications in order even when adapter has variable latency', async () => {
      const deliveryOrder: string[] = [];

      // Adapter with variable delay — first call is slow, second is fast
      let callCount = 0;
      const delayAdapter: NotificationAdapter = {
        channel: 'email' as NotificationChannel,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          callCount++;
          const delay = callCount === 1 ? 50 : 5;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.type);
          return { success: true, channel: 'email', recipient: payload.recipient, deliveredAt: new Date() };
        },
      };

      service.registerAdapter(delayAdapter);

      const orderCreatedEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusChangedEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      // Emit both events sequentially — order:created first, then status change
      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(statusChangedEvent);

      // Despite the first adapter call being slower, notifications must be delivered in order
      expect(deliveryOrder).toEqual(['order_confirmation', 'order_status_update']);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(2);
      expect(notifications[0]?.status).toBe('sent');
      expect(notifications[1]?.status).toBe('sent');
    });
  });
});

